{
  "editor.formatOnSave": true,
  "editor.defaultFormatter": "esbenp.prettier-vscode",
  "[typescript]": {
    "editor.defaultFormatter": "esbenp.prettier-vscode"
  },
  "[html]": {
    "editor.defaultFormatter": "esbenp.prettier-vscode"
  },
  "editor.codeActionsOnSave": {
    "source.fixAll.eslint": "explicit"
  },
  "typescript.tsdk": "node_modules/typescript/lib",
  "angular.enable-strict-mode-prompt": false,
  "files.exclude": {
    "**/.git": true,
    "**/node_modules": true,
    "**/.angular": true
  },
  "search.exclude": {
    "**/node_modules": true,
    "**/dist": true,
    "**/.angular": true
  },
  "editor.tabSize": 2,
  "editor.insertSpaces": true
}

{
  "Angular Input Property": {
    "prefix": "ainput",
    "body": ["@Input() ${1:name}: ${2:string} = ${3:''};"],
    "description": "Angular @Input decorator"
  },
  "Angular Output EventEmitter": {
    "prefix": "aoutput",
    "body": [
      "@Output() ${1:name} = new EventEmitter<${2:void}>();"
    ],
    "description": "Angular @Output EventEmitter"
  }
}

{
  "version": "2.0.0",
  "tasks": [
    {
      "label": "ng serve",
      "type": "shell",
      "command": "ng serve",
      "group": "build",
      "presentation": { "reveal": "always", "panel": "new" },
      "isBackground": true,
      "problemMatcher": {
        "owner": "typescript",
        "pattern": "$tsc",
        "background": {
          "activeOnStart": true,
          "beginsPattern": "Browser application bundle generation complete",
          "endsPattern": "Angular Live Development Server is listening"
        }
      }
    },
    {
      "label": "ng test",
      "type": "shell",
      "command": "ng test --watch",
      "group": "test",
      "presentation": { "reveal": "always", "panel": "new" }
    },
    {
      "label": "ng build",
      "type": "shell",
      "command": "ng build --configuration production",
      "group": { "kind": "build", "isDefault": true }
    }
  ]
}

// Debug: log every change detection cycle for a component
import { ChangeDetectorRef } from '@angular/core';

export class MyComponent implements DoCheck {
  constructor(private cdr: ChangeDetectorRef) {}

  ngDoCheck() {
    console.log('CD cycle', this.cdr);
  }
}
